export const categories: string[] = [
  "Agents and Language",
  "Infra and Distributed",
  "Data and ML",
  "Web and Full-stack",
  "Systems and C++",
  "Developer Tools",
  "Instrumentation and Test",
  "Other",
];

export const languages: string[] = Array.from(new Set(projects.map((p) => p.language))).sort((a, b) => {
  const ca = projects.filter((p) => p.language === a).length;
  const cb = projects.filter((p) => p.language === b).length;
  return cb - ca || a.localeCompare(b);
});

export function getProject(name: string): Project | undefined {
  return projects.find((p) => p.name === name);
}

export const flagshipProjects: Project[] = flagships
  .map((n) => projects.find((p) => p.name === n))
  .filter((p): p is Project => Boolean(p));
